### Complete GitHub Action Logic with API Interaction

Source: https://github.com/actions/toolkit/blob/main/docs/github-package.md

This TypeScript code represents a complete GitHub Action that retrieves inputs for a welcome message and repository token, fetches issue context, and uses Octokit to post a comment if an issue or pull request was opened. It includes error handling.

```typescript
import * as core from '@actions/core';
import * as github from '@actions/github';

export async function run() {
    try {
    const welcomeMessage: string = core.getInput('welcome-message', {required: true});
    const repoToken: string = core.getInput('repo-token', {required: true});
    const issue: {owner: string; repo: string; number: number} = github.context.issue;

    if (github.context.payload.action !== 'opened') {
      console.log('No issue or pull request was opened, skipping');
      return;
    }

    const client: github.GitHub = new github.GitHub(repoToken);
    await client.issues.createComment({
      owner: issue.owner,
      repo: issue.repo,
      issue_number: issue.number,
      body: welcomeMessage
    });
    }
    catch (error) {
      core.setFailed(error.message);
      throw error;
    }
}

run();
```

