### Core Actions: Input, Output, Logging, and Summary with TypeScript

Source: https://context7.com/actions/toolkit/llms.txt

Demonstrates the use of the @actions/core package for managing inputs, setting outputs, logging messages, creating workflow annotations, and generating job summaries in GitHub Actions. It includes input retrieval, logging at different levels, grouping logs, setting outputs, exporting environment variables, adding paths, masking secrets, and writing job summaries.

```typescript
import * as core from '@actions/core';

async function run() {
  try {
    // Get inputs with validation
    const name = core.getInput('who-to-greet', { required: true });
    const enableDebug = core.getBooleanInput('debug-mode');
    const tags = core.getMultilineInput('tags');

    // Log with different levels
    core.info(`Hello ${name}!`);
    core.debug(`Debug mode: ${enableDebug}`);
    core.warning('This is a warning', {
      file: 'app.js',
      startLine: 10
    });

    // Group related log output
    await core.group('Build and Test', async () => {
      core.info('Building project...');
      // Build logic here
      core.info('Running tests...');
      // Test logic here
    });

    // Set outputs for other steps
    core.setOutput('time', new Date().toTimeString());
    core.setOutput('success', true);

    // Export environment variables
    core.exportVariable('BUILD_ID', '12345');
    core.addPath('/usr/local/custom/bin');

    // Mask sensitive data
    core.setSecret('mypassword123');

    // Create job summary
    await core.summary
      .addHeading('Test Results')
      .addTable([
        [{data: 'Test', header: true}, {data: 'Result', header: true}],
        ['Unit Tests', '✅ Passed'],
        ['Integration Tests', '✅ Passed']
      ])
      .addCodeBlock(JSON.stringify({passed: 50, failed: 0}, null, 2), 'json')
      .write();

  } catch (error) {
    core.setFailed(`Action failed: ${error.message}`);
  }
}

run();

```

