### Interact with GitHub API using @actions/github (TypeScript)

Source: https://context7.com/actions/toolkit/llms.txt

This snippet illustrates how to use the @actions/github package to interact with the GitHub API. It utilizes a pre-authenticated Octokit client and the workflow context to perform actions like creating issue comments, fetching pull request details, listing repository contents, executing GraphQL queries, and adding labels to issues.

```typescript
import * as github from '@actions/github';
import * as core from '@actions/core';

async function interactWithGitHub() {
  const token = core.getInput('github-token', { required: true });
  const octokit = github.getOctokit(token);

  // Access workflow context
  const context = github.context;
  core.info(`Event: ${context.eventName}`);
  core.info(`Repository: ${context.repo.owner}/${context.repo.repo}`);
  core.info(`SHA: ${context.sha}`);
  core.info(`Actor: ${context.actor}`);

  try {
    // Create issue comment
    if (context.eventName === 'pull_request') {
      await octokit.rest.issues.createComment({
        ...context.repo,
        issue_number: context.issue.number,
        body: '✅ Tests passed successfully!'
      });
    }

    // Get pull request details
    const { data: pr } = await octokit.rest.pulls.get({
      owner: context.repo.owner,
      repo: context.repo.repo,
      pull_number: 123
    });
    core.info(`PR Title: ${pr.title}`);
    core.info(`Author: ${pr.user.login}`);

    // List repository files
    const { data: contents } = await octokit.rest.repos.getContent({
      ...context.repo,
      path: 'src'
    });

    if (Array.isArray(contents)) {
      contents.forEach(item => {
        core.info(`${item.type}: ${item.name}`);
      });
    }

    // GraphQL query
    const graphqlQuery = `
      query($owner: String!, $repo: String!) {
        repository(owner: $owner, name: $repo) {
          issues(first: 5, states: OPEN) {
            nodes {
              title
              number
              author {
                login
              }
            }
          }
        }
      }
    `;

    const result = await octokit.graphql(graphqlQuery, {
      owner: context.repo.owner,
      repo: context.repo.repo
    });

    result.repository.issues.nodes.forEach(issue => {
      core.info(`#${issue.number}: ${issue.title} (@${issue.author.login})`);
    });

    // Add labels to issue
    await octokit.rest.issues.addLabels({
      ...context.repo,
      issue_number: context.issue.number,
      labels: ['automated', 'needs-review']
    });

  } catch (error) {
    core.setFailed(`GitHub API error: ${error.message}`);
  }
}

interactWithGitHub();

```

